import Name from './Name.js'
import phonebookService from '../services/phonebook.js'

const deleteTogglerById = (id) => {
  phonebookService.deleteName(id)
}

const Persons = ({filteredPeople}) =>{
return(
  <div>
    <ul>
      {filteredPeople.map(name => <Name key = {name.name} person = {name} deletion = {() => deleteTogglerById()}/>)}
    </ul>
  </div>
)}

export default Persons
